"""Find the line of code generated by the model using the block in the version code."""

import ast
import json
import os
import random
import re


def process_line_mask(code_snippet, core_token):
    """Process line mask for code snippet with core token."""
    if not core_token:
        return (None, None)

    lines = code_snippet.split("\n")
    if replaced_lines := _find_replaced_lines(lines, core_token):
        return _create_masked_code(lines, replaced_lines)

    return (None, None)


def _find_replaced_lines(lines: list[str], core_token: str) -> dict[int, str]:
    """Find lines that contain the core token and should be replaced."""
    replaced_lines = {}
    in_multi_line_comment = False

    for i, line in enumerate(lines):
        in_multi_line_comment = _process_line_for_replacement(
            line, i, core_token, replaced_lines, in_multi_line_comment
        )

    return replaced_lines


def _process_line_for_replacement(
    line: str,
    line_index: int,
    core_token: str,
    replaced_lines: dict,
    in_multi_line_comment: bool,
) -> bool:
    """Process a single line for replacement logic."""
    if in_multi_line_comment:
        return _handle_multi_line_comment(line, in_multi_line_comment)
    elif _is_comment_line(line):
        return in_multi_line_comment
    elif _is_single_line_docstring(line):
        return in_multi_line_comment
    elif _starts_multi_line_comment(line):
        return True
    else:
        return _check_for_core_token(
            line, line_index, core_token, replaced_lines, in_multi_line_comment
        )


def _handle_multi_line_comment(line: str, in_multi_line_comment: bool) -> bool:
    """Handle multi-line comment state."""
    if ('"""' in line or "'''" in line) and (
        not re.findall("'''(.*?)'''|\\\"\\\"\\\"(.*?)\\\"\\\"\\\"", line)
    ):
        return False
    return in_multi_line_comment


def _is_comment_line(line: str) -> bool:
    """Check if line is a comment line."""
    return line.strip().startswith("#")


def _is_single_line_docstring(line: str) -> bool:
    """Check if line is a single-line docstring."""
    return bool(re.findall("'''(.*?)'''|\\\"\\\"\\\"(.*?)\\\"\\\"\\\"", line))


def _starts_multi_line_comment(line: str) -> bool:
    """Check if line starts a multi-line comment."""
    return ('"""' in line or "'''" in line) and (
        not re.findall("'''(.*?)'''|\\\"\\\"\\\"(.*?)\\\"\\\"\\\"", line)
    )


def _check_for_core_token(
    line: str,
    line_index: int,
    core_token: str,
    replaced_lines: dict,
    in_multi_line_comment: bool,
) -> bool:
    """Check if line contains core token and should be replaced."""
    if re.search("\\bdef\\s+task_function\\b", line):
        return in_multi_line_comment

    if re.search(f"\x08{re.escape(core_token)}\x08(?!\\s*=)", line):
        replaced_lines[line_index] = line

    return in_multi_line_comment


def _create_masked_code(lines: list[str], replaced_lines: dict) -> tuple[str, str]:
    """Create masked code by replacing a random line."""
    random_line_location = random.choice(list(replaced_lines.keys()))
    masked_line = lines[random_line_location]
    leading_spaces = re.match("^\\s*", masked_line)[0]
    masked_line = masked_line.strip()
    lines[random_line_location] = f"{leading_spaces}<line_mask>"
    masked_code = "\n".join(lines)
    return (masked_code, masked_line)


def load_json(file_path):
    with open(file_path, "r", encoding="utf-8") as f:
        data = json.load(f)
    return data


def save_json(file_path, data):
    with open(file_path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=4)


if __name__ == "__main__":
    model_list = os.listdir("../data/result_data/block_completion")
    for model in model_list:
        input_json_file = f"../data/result_data/block_completion/{model}/VersiCode_block_completion.json"
        output_json_file = input_json_file
        data = load_json(input_json_file)
        for item in data:
            core_token = item["core_token"]
            code = item["code"]
            _, core_line_in_code = process_line_mask(code, core_token)
            item["core_line_in_code"] = core_line_in_code or "N/A"
            model_output_clear = item["model_output_clear"]
            core_line_in_output_list = []
            for entry in ast.literal_eval(model_output_clear):  # nosec B307
                _, core_line_in_output = process_line_mask(entry, core_token)
                if core_line_in_output:
                    core_line_in_output_list.append(core_line_in_output)
                else:
                    core_line_in_output_list.append("N/A")
            item["core_line_in_output_clear"] = core_line_in_output_list
        save_json(output_json_file, data)
        print("Done!")
